import{c as r,Q as a,j as n,m as t}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Agentic Harness for Real-World Compilers","description":"","frontmatter":{"title":"Agentic Harness for Real-World Compilers","arxiv_id":2603.20075,"authors":"Yingwei Zheng, Cong Li, Shaohua Li, Yuqun Zhang, Zhendong Su","published":"2026-03-20T00:00:00.000Z","source":"https://arxiv.org/abs/2603.20075","source_tier":"P"},"headers":[],"relativePath":"research/papers/2026-03-20-agentic-harness-real-world-compilers-2603-20075.md","filePath":"research/papers/2026-03-20-agentic-harness-real-world-compilers-2603-20075.md","lastUpdated":1779901665000}'),s={name:"research/papers/2026-03-20-agentic-harness-real-world-compilers-2603-20075.md"};function o(i,e,l,h,g,d){return a(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="agentic-harness-for-real-world-compilers" tabindex="-1">Agentic Harness for Real-World Compilers <a class="header-anchor" href="#agentic-harness-for-real-world-compilers" aria-label="Permalink to &quot;Agentic Harness for Real-World Compilers&quot;">​</a></h1><p><strong>ArXiv</strong>: 2603.20075 | <strong>Date</strong>: 2026-03-20 | <strong>Authors</strong>: Yingwei Zheng, Cong Li, Shaohua Li, Yuqun Zhang, Zhendong Su | <strong>Category</strong>: cs.SE</p><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>首篇針對 LLM agent 理解和修復編譯器 bug 的 agentic harness 設計，以 LLVM（工業廣泛使用的編譯器基礎設施）為目標。揭示 frontier LLM 在編譯器問題上相比一般軟體 bug 存在<strong>顯著性能差距</strong>。</p><h2 id="核心組件-llvm-autofix-系統" tabindex="-1">核心組件：llvm-autofix 系統 <a class="header-anchor" href="#核心組件-llvm-autofix-系統" aria-label="Permalink to &quot;核心組件：llvm-autofix 系統&quot;">​</a></h2><ol><li><strong>Agent-friendly LLVM tools</strong>：專為 LLM-compiler 互動設計的工具集</li><li><strong>llvm-bench</strong>：可重現 LLVM bug 基準測試集</li><li><strong>llvm-autofix-mini</strong>：專業化自動修復 agent</li></ol><h2 id="主要量化發現" tabindex="-1">主要量化發現 <a class="header-anchor" href="#主要量化發現" aria-label="Permalink to &quot;主要量化發現&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指標</th><th>結果</th></tr></thead><tbody><tr><td>Frontier LLM 在編譯器 vs 一般軟體 bug 的性能差距</td><td><strong>-60%</strong> 性能退化</td></tr><tr><td>llvm-autofix-mini vs SOTA 替代方案</td><td><strong>+22%</strong> 性能提升</td></tr></tbody></table><h2 id="核心洞察-域特化工具集的必要性" tabindex="-1">核心洞察：域特化工具集的必要性 <a class="header-anchor" href="#核心洞察-域特化工具集的必要性" aria-label="Permalink to &quot;核心洞察：域特化工具集的必要性&quot;">​</a></h2><p>編譯器 bug 的獨特挑戰：</p><ul><li>高技術複雜性</li><li>需要專業領域知識</li><li>歷史上 bug 文件稀疏或缺乏資訊</li></ul><p><strong>一般 LLM 方法在專業工程域顯著退化</strong>，需要域特化 harness。</p><h2 id="對-harness-engineering-的意義" tabindex="-1">對 Harness Engineering 的意義 <a class="header-anchor" href="#對-harness-engineering-的意義" aria-label="Permalink to &quot;對 Harness Engineering 的意義&quot;">​</a></h2><p>與其他 harness 論文形成重要補充：</p><ul><li>大多數 harness 研究聚焦通用軟體工程（SWE-bench）</li><li>本文展示<strong>域特化 harness 設計</strong>的必要性</li><li>60% 性能退化 = harness 工程在專業域的最大已知改進空間</li></ul><h3 id="harness-設計模式啟示" tabindex="-1">Harness 設計模式啟示 <a class="header-anchor" href="#harness-設計模式啟示" aria-label="Permalink to &quot;Harness 設計模式啟示&quot;">​</a></h3><ol><li><strong>工具域適配</strong>：工具必須對目標域的知識和語言友好</li><li><strong>基準域對齊</strong>：評估基準需反映真實的域特定挑戰</li><li><strong>Agent 特化</strong>：通用 agent 不如域特化 agent</li></ol><h2 id="分類" tabindex="-1">分類 <a class="header-anchor" href="#分類" aria-label="Permalink to &quot;分類&quot;">​</a></h2><p><strong>Harness Engineering</strong> — 編譯器工程域的 agentic harness 研究，60% 域特化性能退化是最大的已知未開發 harness 優化空間，展示了域特化 harness 設計的必要性。</p>',19)])])}const p=r(s,[["render",o]]);export{u as __pageData,p as default};
